import 'dart:io';import 'package:image/image.dart' as img;void main() { final image = img.Image(width: 512, height: 512); img.fill(image, color: img.ColorRgb8(18, 108, 85)); img.fillRect(image, x1: 100, y1: 200, x2: 412, y2: 430, color: img.ColorRgb8(255, 255, 255)); img.fillRect(image, x1: 156, y1: 110, x2: 356, y2: 180, color: img.ColorRgb8(230, 230, 230)); img.fillRect(image, x1: 200, y1: 40, x2: 312, y2: 110, color: img.ColorRgb8(255, 255, 255)); for (int i = 0; i < 3; i++) { for (int j = 0; j < 4; j++) { img.fillRect(image, x1: 130 + i * 90, y1: 230 + j * 45, x2: 200 + i * 90, y2: 260 + j * 45, color: img.ColorRgb8(18, 108, 85)); } } File('assets/icon.png').writeAsBytesSync(img.encodePng(image)); print('Saved.'); }
